static ui_boot_logo_t s_current_logo = {
    s_boot_logo_black_200x80,
    200u,
    80u
};

void UI_Boot_SetLogo(const uint8_t *bits, uint16_t width, uint16_t height)
{
    if ((bits == 0) || (width == 0u) || (height == 0u))
    {
        s_current_logo.bits = s_boot_logo_black_200x80;
        s_current_logo.width = 200u;
        s_current_logo.height = 80u;
        return;
    }

    s_current_logo.bits = bits;
    s_current_logo.width = width;
    s_current_logo.height = height;
}

void UI_Boot_GetLogo(ui_boot_logo_t *out_logo)
{
    if (out_logo == 0)
    {
        return;
    }

    *out_logo = s_current_logo;
}

void UI_Boot_Draw(u8g2_t *u8g2)
{
    int16_t x;
    int16_t y;

    if ((u8g2 == 0) || (s_current_logo.bits == 0))
    {
        return;
    }

    x = (int16_t)((UI_LCD_W - s_current_logo.width) / 2);
    y = (int16_t)((UI_LCD_H - s_current_logo.height) / 2);

    if (x < 0)
    {
        x = 0;
    }
    if (y < 0)
    {
        y = 0;
    }

    u8g2_SetDrawColor(u8g2, 1);
    u8g2_DrawXBM(u8g2,
                 (u8g2_uint_t)x,
                 (u8g2_uint_t)y,
                 s_current_logo.width,
                 s_current_logo.height,
                 s_current_logo.bits);
}
